parameters.jsCode:
// Pull the structured output from the OpenAI Responses API envelope
const responseBody = $input.item.json;

// The Responses API returns output[0].content[0].text for text responses
let rawText;
try {
  rawText = responseBody.output[0].content[0].text;
} catch (e) {
  throw new Error('Unexpected OpenAI response shape: ' + JSON.stringify(responseBody));
}

// Parse the strict JSON the model was forced to return
let extracted;
try {
  extracted = JSON.parse(rawText);
} catch (e) {
  throw new Error('OpenAI returned non-JSON: ' + rawText);
}

const {
  invoice_number,
  vendor_name,
  invoice_date,
  due_date,
  total_amount,
  currency,
  line_items,
  notes,
  confidence
} = extracted;

// Required fields for review routing
const REQUIRED = ['invoice_number', 'vendor_name', 'total_amount'];
const missingFields = REQUIRED.filter(f => extracted[f] == null);

// Route to human review if confidence is not high OR any required field is missing
const needs_review = confidence !== 'high' || missingFields.length > 0;

// Build a human-readable reason for the review sheet
let review_reason = null;
if (needs_review) {
  const reasons = [];
  if (confidence !== 'high') reasons.push(`confidence=${confidence}`);
  if (missingFields.length > 0) reasons.push(`missing: ${missingFields.join(', ')}`);
  review_reason = reasons.join('; ');
}

// Serialize line_items as a compact JSON string (one cell in Sheets)
const line_items_json = line_items ? JSON.stringify(line_items) : null;

// Grab email + attachment metadata from the Gmail trigger (two items up in the chain)
const emailData = $('Gmail Trigger').item.json;
const binaryData = $input.item.binary?.data || {};
const attachment_filename = binaryData.fileName || binaryData.fileExtension
  ? `${binaryData.fileName || 'attachment'}`
  : 'unknown';

return [{
  json: {
    // Metadata
    timestamp: new Date().toISOString(),
    email_from: emailData.from,
    email_subject: emailData.subject,
    attachment_filename,

    // Extracted fields
    invoice_number,
    vendor_name,
    invoice_date,
    due_date,
    total_amount,
    currency,
    line_items_json,
    notes,
    confidence,

    // Routing
    needs_review,
    review_reason,

    // Raw response for audit trail
    raw_json: rawText
  }
}];

